import{toEntry}from"../../util/input.js";import{isAbsolute,join}from"../../util/path.js";import{hasDependency}from"../../util/plugin.js";import{configFiles,inputsFromFrameworks,inputsFromPlugins,loadConfig}from"./helpers.js";const title="Karma",enablers=["karma"],isEnabled=({dependencies:e})=>hasDependency(e,enablers),config=configFiles,resolveConfig=async(e,n)=>{const o=new Set,i=loadConfig(e);if(!i)return[];i.frameworks&&inputsFromFrameworks(i.frameworks).forEach(o.add,o),inputsFromPlugins(i.plugins,n.manifest.devDependencies).forEach(o.add,o);const s=i.basePath??"";if(i.files)for(const e of i.files){const i="string"==typeof e?e:e.pattern,r=isAbsolute(i)?i:join(n.configFileDir,s,i);o.add(toEntry(r))}if(i.exclude)for(const e of i.exclude){const i=isAbsolute(e)?e:join(n.configFileDir,s,e);o.add(toEntry(`!${i}`))}return Array.from(o)},plugin={title:title,enablers:enablers,isEnabled:isEnabled,config:config,resolveConfig:resolveConfig};export default plugin;